import { useQuery } from "@tanstack/react-query";
import { SessionHeader } from "./SessionHeader";
import { ConversationList } from "./conversation/ConversationList";
import { sessionDetailQuery } from "~/lib/queries/sessions";
import { useSession } from "~/hooks/useSession";
import { Card, CardContent, CardHeader, CardTitle } from "~/components/ui/card";

interface SessionDetailPageProps {
  sessionId: string;
}

export function SessionDetailPage({ sessionId }: SessionDetailPageProps) {
  const { data, isLoading, error } = useQuery(sessionDetailQuery(sessionId));

  if (isLoading) {
    return (
      <div className="flex flex-col h-full">
        <div className="border-b p-4 space-y-3">
          <div className="h-8 w-48 bg-muted animate-pulse rounded" />
          <div className="h-4 w-64 bg-muted animate-pulse rounded" />
          <div className="h-6 w-96 bg-muted animate-pulse rounded" />
        </div>
        <div className="flex-1 p-4">
          <div className="space-y-4">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="h-24 bg-muted animate-pulse rounded" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="flex items-center justify-center h-96">
        <Card className="max-w-md w-full">
          <CardHeader>
            <CardTitle className="text-destructive">
              Error Loading Session
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground">
              Failed to load session data. The session may not exist.
            </p>
          </CardContent>
        </Card>
      </div>
    );
  }

  return <SessionDetailContent session={data.session} />;
}

interface SessionDetailContentProps {
  session: {
    sessionId: string;
    projectPath: string;
    repository: string | null;
    sessionDate: string;
    userId: string;
    userName: string | null;
    skills: Array<string>;
    slashCommands: Array<string>;
    subagentTypes: Array<string>;
    content: string;
    subagents: Record<string, string>;
  };
}

function SessionDetailContent({ session }: SessionDetailContentProps) {
  const { conversations, getToolResult, subagents } = useSession(session);

  return (
    <div className="flex flex-col h-full">
      <SessionHeader session={session} />
      <div className="flex-1 overflow-auto p-4">
        <ConversationList
          conversations={conversations}
          getToolResult={getToolResult}
          subagents={subagents}
        />
      </div>
    </div>
  );
}

