import { useState } from "react";
import { Check, Clock, Copy, FolderOpen, GitBranch, User } from "lucide-react";
import { Badge } from "~/components/ui/badge";
import { Button } from "~/components/ui/button";
import { formatRelativeTime } from "~/lib/alert-time-utils";

interface SessionHeaderProps {
  session: {
    sessionId: string;
    projectPath: string;
    repository: string | null;
    sessionDate: string;
    userId: string;
    userName: string | null;
    skills: Array<string>;
    slashCommands: Array<string>;
    subagentTypes: Array<string>;
  };
}

export function SessionHeader({ session }: SessionHeaderProps) {
  const [copied, setCopied] = useState(false);

  // Deduplicate primitives
  const uniqueSkills = [...new Set(session.skills)];
  const uniqueCommands = [...new Set(session.slashCommands)];
  const uniqueAgents = [...new Set(session.subagentTypes)];

  function handleCopy() {
    navigator.clipboard.writeText(session.sessionId);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  return (
    <div className="border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60 sticky top-0 z-10">
      <div className="px-4 py-2 space-y-1.5">
        {/* Session ID */}
        <div className="flex items-center gap-2">
          <h1 className="text-base font-semibold truncate font-mono">
            {session.sessionId}
          </h1>
          <Button
            variant="ghost"
            size="sm"
            className="h-6 w-6 p-0"
            onClick={handleCopy}
          >
            {copied ? (
              <Check className="h-3.5 w-3.5 text-green-500" />
            ) : (
              <Copy className="h-3.5 w-3.5 text-muted-foreground" />
            )}
          </Button>
        </div>

        {/* Metadata row */}
        <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
          {session.repository && (
            <div className="flex items-center gap-1">
              <GitBranch className="h-4 w-4" />
              <span className="truncate max-w-[200px]" title={session.repository}>
                {session.repository}
              </span>
            </div>
          )}
          <div className="flex items-center gap-1">
            <FolderOpen className="h-4 w-4" />
            <span className="truncate max-w-[300px]" title={session.projectPath}>
              {session.projectPath}
            </span>
          </div>
          <div className="flex items-center gap-1">
            <Clock className="h-4 w-4" />
            <span>{formatRelativeTime(session.sessionDate)}</span>
          </div>
          <div className="flex items-center gap-1">
            <User className="h-4 w-4" />
            <span>{session.userName ?? session.userId.slice(0, 8) + "..."}</span>
          </div>
        </div>

        {/* Primitives row */}
        {(uniqueSkills.length > 0 ||
          uniqueCommands.length > 0 ||
          uniqueAgents.length > 0) && (
          <div className="flex flex-wrap gap-1">
            {uniqueSkills.map((skill) => (
              <Badge key={`skill-${skill}`} variant="secondary" className="text-xs">
                skill:{skill}
              </Badge>
            ))}
            {uniqueCommands.map((cmd) => (
              <Badge key={`cmd-${cmd}`} variant="outline" className="text-xs">
                /{cmd}
              </Badge>
            ))}
            {uniqueAgents.map((type) => (
              <Badge key={`agent-${type}`} variant="default" className="text-xs">
                agent:{type}
              </Badge>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

