101→export function formatBashSummary(input: BashInput): string {
102→  // Extract the actual command, stripping long paths
103→  const cmd = input.command;
104→
105→  // If there's a description, prefer that
106→  if (input.description) {
107→    return input.description;
108→  }
109→
110→  // Otherwise show truncated command
111→  return cmd.length > 60 ? cmd.slice(0, 60) + "..." : cmd;
112→}
