 62→          <div className="flex items-center gap-2">
 63→            {result.status === "timeout" ? (
 64→              <>
 65→                <Clock className="h-4 w-4 text-yellow-500" />
 66→                <span className="text-sm text-yellow-600 dark:text-yellow-400 font-medium">
 67→                  Timeout - Agent still running
 68→                </span>
 69→              </>
 70→            ) : result.taskStatus === "running" ? (
 71→              <>
 72→                <Loader2 className="h-4 w-4 text-blue-500 animate-spin" />
 73→                <span className="text-sm text-blue-600 dark:text-blue-400 font-medium">
 74→                  Running
 75→                </span>
 76→              </>
 77→            ) : result.taskStatus === "completed" ? (
 78→              <>
 79→                <CheckCircle2 className="h-4 w-4 text-green-500" />
 80→                <span className="text-sm text-green-600 dark:text-green-400 font-medium">
 81→                  Completed
 82→                </span>
