 86→                <AlertTriangle className="h-4 w-4 text-muted-foreground" />
 87→                <span className="text-sm text-muted-foreground">
 88→                  Unknown status
 89→                </span>
 90→              </>
 91→            )}
 92→          </div>
 93→
 94→          {/* Task description */}
 95→          {result.description && (
 96→            <p className="text-xs text-muted-foreground">{result.description}</p>
 97→          )}
 98→
