100→          {result.output && (
101→            <div>
102→              <h4 className="text-xs font-medium text-muted-foreground mb-0.5">
103→                Agent Activity
104→              </h4>
105→              <div className="bg-background/50 p-2 rounded-md border text-xs max-h-48 overflow-y-auto">
106→                {formatAgentOutput(result.output)}
107→              </div>
108→            </div>
109→          )}
110→
111→          {/* Final result */}
112→          {result.finalResult && (
113→            <div>
114→              <h4 className="text-xs font-medium text-muted-foreground mb-0.5">
115→                Result
116→              </h4>
117→              <pre className="text-xs bg-background/50 p-2 rounded-md border overflow-x-auto whitespace-pre-wrap max-h-48 overflow-y-auto">
118→                {result.finalResult}
119→              </pre>
120→            </div>
121→          )}
122→        </div>
123→      )}
124→    </div>
125→  );
126→}
127→
128→export function formatTaskOutputSummary(
129→  input: TaskOutputInput,
130→  toolResult: ToolResultContent | undefined
131→): string {
132→  const result = parseTaskOutputResult(toolResult);
133→
134→  // Prefer showing the task description over the ID
135→  const label = result?.description || input.task_id;
136→  const truncatedLabel = label.length > 40 ? label.slice(0, 40) + "..." : label;
137→
138→  if (!result) return truncatedLabel;
139→
140→  // Add status indicator
141→  if (result.status === "timeout") {
142→    return `${truncatedLabel} ⏳`;
143→  }
144→  if (result.taskStatus === "running") {
145→    return `${truncatedLabel} ⏳`;
146→  }
147→  if (result.taskStatus === "completed") {
148→    return `${truncatedLabel} ✓`;
149→  }
150→  return truncatedLabel;
151→}
152→
153→interface ParsedResult {
154→  status?: "timeout" | "success";
155→  taskStatus?: "running" | "completed";
156→  description?: string;
157→  output?: string;
158→  finalResult?: string;
159→}
160→
161→function parseTaskOutputResult(
162→  toolResult: ToolResultContent | undefined
163→): ParsedResult | null {
164→  if (!toolResult) return null;
165→
166→  const content = toolResult.content;
167→
168→  // Handle string content
169→  if (typeof content === "string") {
170→    const isTimeout = content.includes("timeout");
171→    const isRunning = content.includes("running");
172→    const isCompleted = content.includes("completed");
173→
174→    return {
175→      status: isTimeout ? "timeout" : "success",
176→      taskStatus: isRunning ? "running" : isCompleted ? "completed" : undefined,
177→      output: content,
178→    };
179→  }
180→
181→  // Handle array content
182→  if (Array.isArray(content)) {
183→    const text = content
184→      .filter((block): block is { type: "text"; text: string } => block.type === "text")
185→      .map((block) => block.text)
186→      .join("\n");
187→
188→    return parseTaskOutputResult({ ...toolResult, content: text });
189→  }
190→
191→  // Handle object content (structured result)
192→  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- runtime content may be object
193→  if (typeof content === "object" && content !== null) {
194→    const obj = content as TaskOutputResult;
195→    return {
196→      status: obj.retrieval_status,
197→      taskStatus: obj.task?.status,
198→      description: obj.task?.description,
199→      output: obj.task?.output,
200→      finalResult: obj.task?.result,
201→    };
