import { orpcClient } from "~/lib/orpc-client";

interface SessionListFilters {
  page: number;
  pageSize: number;
  projectPath?: string;
  repository?: string;
  userId?: string;
  skills?: Array<string>;
  slashCommands?: Array<string>;
  subagentTypes?: Array<string>;
  startDate?: string;
  endDate?: string;
  sortBy?: "sessionDate" | "ingestedAt";
  sortOrder?: "asc" | "desc";
}

export function sessionsListQuery(filters: SessionListFilters) {
  return {
    queryKey: ["sessions", "list", filters] as const,
    queryFn: async () => {
      return orpcClient.compound.listSessions({
        page: filters.page,
        limit: filters.pageSize,
        projectPath: filters.projectPath,
        repository: filters.repository,
        userId: filters.userId,
        skills: filters.skills,
        slashCommands: filters.slashCommands,
        subagentTypes: filters.subagentTypes,
        startDate: filters.startDate,
        endDate: filters.endDate,
        sortBy: filters.sortBy,
        sortOrder: filters.sortOrder,
      });
    },
    staleTime: 2 * 60 * 1000, // 2 minutes
  };
}

export function sessionFilterOptionsQuery() {
  return {
    queryKey: ["sessions", "filterOptions"] as const,
    queryFn: async () => {
      return orpcClient.compound.getSessionFilterOptions({});
    },
  };
}

export function sessionDetailQuery(sessionId: string) {
  return {
    queryKey: ["sessions", "detail", sessionId] as const,
    queryFn: async () => {
      return orpcClient.compound.getSession({ sessionId });
    },
  };
}

