/**
 * Formats a date string into a relative time string (e.g., "5m ago", "2h ago")
 * Assumes input dates are UTC (from ClickHouse) and appends 'Z' if needed.
 */
export function formatRelativeTime(date: string): string {
  const now = new Date();
  // ClickHouse returns dates like "2026-01-15 21:04:26.247" without timezone.
  // Append 'Z' to indicate UTC, otherwise JS parses as local time.
  const utcDate = date.includes("Z") || date.includes("+") ? date : `${date}Z`;
  const past = new Date(utcDate);
  const diffMs = now.getTime() - past.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);

  if (diffMins < 1) return "just now";
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays < 30) return `${diffDays}d ago`;
  return past.toLocaleDateString();
}

/**
 * Formats the duration an alert has been or was open
 * For open alerts: calculates now - triggeredAt
 * For closed alerts: calculates closedAt - triggeredAt
 */
export function formatOpenDuration(
  triggeredAt: string,
  closedAt: string | null,
): string {
  const triggered = new Date(triggeredAt);
  const endTime = closedAt ? new Date(closedAt) : new Date();

  const diffMs = endTime.getTime() - triggered.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);

  if (diffMins < 1) return "< 1m";
  if (diffMins < 60) return `${diffMins}m`;
  if (diffHours < 24) return `${diffHours}h`;
  return `${diffDays}d`;
}

