export interface SessionDetail {
	session_id: string;
	user_id: string;
	session_date: string;
	last_interaction_date: string;
	project_path: string;
	repository: string | null;
	content: string;
	subagents: Record<string, string>;
	skills: string[];
	slash_commands: string[];
	git_branch: string | null;
	git_sha: string | null;
	total_tokens: number;
	input_tokens: number;
	output_tokens: number;
	success_score?: number;
	duration_min?: number;
	total_interactions?: number;
}

/**
 * Get session analytics from the materialized view
 */
export async function getSessionAnalytics(
	orgId: string,
	params: {
		days?: number;
		user_id?: string;
		project_path?: string;
		repository?: string;
		limit?: number;
		offset?: number;
		sort_by?: "date" | "duration" | "interactions";
		sort_order?: "asc" | "desc";
	} = {},
): Promise<SessionAnalytics[]> {
	const {
		days = 30,
		user_id,
		project_path,
		repository,
		limit = 50,
		offset = 0,
		sort_by = "date",
		sort_order = "desc",
	} = params;

	const org = escapeString(orgId);
	const d = Number(days);

