import { z } from "zod";

// Content block schemas
export const TextContentSchema = z.object({
	type: z.literal("text"),
	text: z.string(),
});

export const ThinkingContentSchema = z.object({
	type: z.literal("thinking"),
	thinking: z.string(),
	signature: z.string().optional(),
});

export const ToolUseContentSchema = z.object({
	type: z.literal("tool_use"),
	id: z.string(),
	name: z.string(),
	input: z.record(z.string(), z.unknown()),
});

export const ToolResultContentSchema = z.object({
	type: z.literal("tool_result"),
	tool_use_id: z.string(),
	content: z.union([
		z.string(),
		z.array(
			z.union([
				TextContentSchema,
				z.object({ type: z.literal("image"), source: z.unknown() }),
			]),
		),
	]),
	is_error: z.boolean().optional(),
});

// Message schemas
export const UserMessageSchema = z.object({
	role: z.literal("user"),
	content: z.union([
		z.string(),
		z.array(
			z.union([z.string(), TextContentSchema, ToolResultContentSchema]),
		),
	]),
});

export const AssistantMessageSchema = z.object({
	role: z.literal("assistant"),
	content: z.array(
		z.union([
			TextContentSchema,
			ThinkingContentSchema,
			ToolUseContentSchema,
		]),
	),
});

// Entry schemas
const BaseEntrySchema = z.object({
	uuid: z.string(),
	timestamp: z.string(),
	sessionId: z.string(),
});

export const UserEntrySchema = BaseEntrySchema.extend({
	type: z.literal("user"),
	message: UserMessageSchema,
});

export const AssistantEntrySchema = BaseEntrySchema.extend({
	type: z.literal("assistant"),
	message: AssistantMessageSchema,
});

export const SummaryEntrySchema = z.object({
	type: z.literal("summary"),
	summary: z.string(),
});

export const SystemEntrySchema = BaseEntrySchema.extend({
	type: z.literal("system"),
	message: z.object({ content: z.string() }),
});

// Union type
export const ConversationSchema = z.union([
	UserEntrySchema,
	AssistantEntrySchema,
	SummaryEntrySchema,
	SystemEntrySchema,
]);

export type TextContent = z.infer<typeof TextContentSchema>;
export type ThinkingContent = z.infer<typeof ThinkingContentSchema>;
export type ToolUseContent = z.infer<typeof ToolUseContentSchema>;
export type ToolResultContent = z.infer<typeof ToolResultContentSchema>;
export type UserEntry = z.infer<typeof UserEntrySchema>;
export type AssistantEntry = z.infer<typeof AssistantEntrySchema>;
export type SummaryEntry = z.infer<typeof SummaryEntrySchema>;
export type SystemEntry = z.infer<typeof SystemEntrySchema>;
export type Conversation = z.infer<typeof ConversationSchema>;

// Parser
export function parseConversations(content: string): Array<Conversation> {
	const conversations: Array<Conversation> = [];
	const lines = content.split("\n").filter(Boolean);

	for (const line of lines) {
		try {
			const parsed = JSON.parse(line) as unknown;
			const result = ConversationSchema.safeParse(parsed);
			if (result.success) {
				conversations.push(result.data);
			}
		} catch {
			// Skip malformed lines
		}
	}

	return conversations;
}

/**
 * Parses slash command XML tags from a user message content.
 *
 * User messages containing slash commands have this format:
 * <command-message>code:research_codebase</command-message>
 * <command-name>/code:research_codebase</command-name>
 * <command-args>argument text here</command-args>
 *
 * The expanded slash command content may be in a separate text block within the same message.
 */

export interface ParsedSlashCommand {
	/** The command message (e.g., "code:research_codebase") */
	commandMessage: string;
	/** The command name with leading slash (e.g., "/code:research_codebase") */
	commandName: string;
	/** The command arguments/prompt text */
	commandArgs: string;
	/** The expanded slash command content (from a separate text block) */
	expandedContent?: string;
}

type MessageContent =
	| string
	| Array<string | { type: "text"; text: string } | { type: string }>;

/**
 * Extract all text content from a user message, returning an array of text strings.
 */
function extractTextBlocks(content: MessageContent): Array<string> {
	if (typeof content === "string") {
		return [content];
	}

	return content
		.filter(
			(block): block is string | { type: "text"; text: string } =>
				typeof block === "string" ||
				(typeof block === "object" && block.type === "text"),
		)
		.map((block) => (typeof block === "string" ? block : block.text));
}

/**
 * Parse slash command from a user message.
 * Handles both string content and array content with multiple text blocks.
 * Returns the parsed command if found, otherwise null.
 */
export function parseSlashCommand(
	content: MessageContent,
): ParsedSlashCommand | null {
	const textBlocks = extractTextBlocks(content);
	if (textBlocks.length === 0) return null;

	// Find the block that contains command tags
	const commandBlockIndex = textBlocks.findIndex((block) =>
		/<command-name>/.test(block),
	);
	if (commandBlockIndex === -1) return null;

	const commandBlock = textBlocks[commandBlockIndex];

	const commandMessageMatch = commandBlock.match(
		/<command-message>([^<]*)<\/command-message>/,
	);
	const commandNameMatch = commandBlock.match(
		/<command-name>([^<]*)<\/command-name>/,
	);
	const commandArgsMatch = commandBlock.match(
		/<command-args>([\s\S]*?)<\/command-args>/,
	);

	if (!commandNameMatch) return null;

	// Collect expanded content from other text blocks (those without command tags)
	const expandedBlocks = textBlocks.filter(
		(_, index) => index !== commandBlockIndex,
	);
	const expandedContent =
		expandedBlocks.length > 0 ? expandedBlocks.join("\n") : undefined;

	return {
		commandMessage: commandMessageMatch?.[1] ?? "",
		commandName: commandNameMatch[1],
		commandArgs: commandArgsMatch?.[1] ?? "",
		expandedContent,
	};
}

/**
 * Check if a user message content contains slash command tags.
 */
export function isSlashCommandMessage(content: MessageContent): boolean {
	const textBlocks = extractTextBlocks(content);
	return textBlocks.some((block) => /<command-name>/.test(block));
}

import { useMemo } from "react";
import type { Conversation, ToolResultContent } from "@/lib/conversation-schema";
import { parseConversations } from "@/lib/conversation-schema";

interface Session {
	content: string;
	subagents: Record<string, string>;
}

function isToolResult(
	block: string | { type: "text"; text: string } | ToolResultContent,
): block is ToolResultContent {
	return typeof block === "object" && block.type === "tool_result";
}

export function useSession(session: Session) {
	const { conversations, toolResultMap } = useMemo(() => {
		const parsed = parseConversations(session.content);
		const resultMap = new Map<string, ToolResultContent>();

		// Build tool result map from user entries
		for (const conv of parsed) {
			if (conv.type === "user" && Array.isArray(conv.message.content)) {
				for (const block of conv.message.content) {
					if (isToolResult(block)) {
						resultMap.set(block.tool_use_id, block);
					}
				}
			}
		}

		return { conversations: parsed, toolResultMap: resultMap };
	}, [session.content]);

	const getToolResult = (toolUseId: string) => toolResultMap.get(toolUseId);

	const subagents = useMemo(() => {
		const result = new Map<string, Array<Conversation>>();
		for (const [agentId, content] of Object.entries(session.subagents)) {
			result.set(agentId, parseConversations(content));
		}
		return result;
	}, [session.subagents]);

	return { conversations, getToolResult, subagents };
}

