							</>
						) : (
							<>
								<AlertTriangle className="h-4 w-4 text-muted-foreground" />
								<span className="text-sm text-muted-foreground">
									Unknown status
								</span>
							</>
						)}
					</div>

					{/* Task description */}
					{result.description && (
